impl Solution { pub fn corp_flight_bookings(black_b: Vec<Vec<i32>>, black_n: i32) -> Vec<i32> { let mut black_res = vec![0; black_n as usize]; for black_v in black_b { black_res[(black_v[0]-1) as usize] += black_v[2]; if black_v[1] < black_n { black_res[black_v[1] as usize] -= black_v[2]; } } for black_i in 1..black_n as usize { black_res[black_i] += black_res[black_i-1]; } black_res } }